INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ヒヨリでっす♪\n元気いっぱいがんばるよ♪", 0, 1, 0, "ねぇねぇ、騎士クン\n手伝ってあげようよ～", 2, 1.4, "お！\nあそこに困ってそうな人発見！", 0, 0, 1, 1, 1001, 0, "春咲 ひより");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("みんなみたいに\nわたしも強くならなきゃ", 0, 1, 0, "わ、わたし、\nなに言ってるんだろ\nあはは…", 2, 1.4, "大切な人を\n守れるようになりたい…って", 0, 0, 1, 1, 1002, 0, "草野 優衣");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("フェンシングを始めてみては？", 0, 1, 0, "少しは磨かれると思いますよ。", 2, 1.4, "キミに必要な集中力と感性が", 0, 0, 1, 1, 1003, 0, "士条 怜");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ねぇ、にいちゃん！", 0, 1, 0, "みそぎはねぇ、\nかくれんぼやりたい！", 2, 1.5, "今日はなにして遊ぶ？", 0, 0, 1, 1, 1004, 0, "穂高 みそぎ");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("風宮あかりです", 0, 1, 0, "私といっしょに…\nいかない？", 2, 1.4, "ねぇ…", 0, 0, 1, 1, 1006, 0, "風宮 あかり");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("出雲宮子なのー", 0, 1, 0, "食べ物の恨みは怖いのー", 2, 1.5, "プリンたべたいのー", 0, 0, 1, 1, 1007, 0, "出雲 宮子");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ボクは虹村雪。", 0, 1, 0, "いいよ。\n見られることは運命さ…", 2, 1.4, "キミもボクの美貌に\n吸い寄せられたんだね。", 0, 0, 1, 1, 1008, 0, "虹村 雪");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("フッ…聞いて後悔するがいい！", 0, 1, 0, "人呼んで「疾風の冥姫」!!", 2, 1.4, "我が真名は\nアンネローゼ・フォン・シュテッヒパルム！", 0, 0, 1, 1, 1009, 0, "柊杏奈");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("マホマホ王国のプリンセス、\nまほ姫どす", 0, 1, 0, "ほんまおおきにやわ～♪", 2, 1.5, "うさぎさん、\n運命の王子はんに巡りあわせてくれて", 0, 0, 1, 1, 1010, 0, "姫宮 真歩");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("衣之咲璃乃です！", 0, 1, 0, "ここで会ったが\n100年目～！", 2, 1.4, "生き別れたお兄ちゃんを探して\n三千世界！", 0, 0, 1, 1, 1011, 0, "衣之咲 璃乃");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("私はハツネ、\n結構強いんだよ。\nきらーん☆", 0, 1, 0, "…って、お願い！\n誰にも言わないでおいて～！", 2, 1.4, "ち、超能力って…\n何のことかな～？", 0, 0, 1, 1, 1012, 0, "柏崎 初音");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ちょす！\n美波鈴奈だよ～♪", 0, 1, 0, "ヒデサイまぢ\nGF（グッドフィーリング）～♪", 2, 1.4, "一応カリスマ読モJKやってまっす！", 0, 0, 1, 1, 1016, 0, "美波 鈴奈");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("はいたーい。\n喜屋武香織さー。", 0, 1, 0, "でも、沖縄もとってもいいとこさー", 2, 1.4, "東京は遊園地みたいなところさー", 0, 0, 1, 1, 1017, 0, "喜屋武 香織");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("支倉伊緒です。", 0, 1, 0, "イオちゃんって呼んでね。", 2, 1.4, "先生って呼ばれるのは\nくすぐったいから", 0, 0, 1, 1, 1018, 0, "支倉 伊緒");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ふえ…？\nミミ、むずかしいこと\nよくわかんない…", 0, 1, 0, "ミミをおいてかないでぇ～", 2, 1.5, "あ！/\お兄ちゃ～ん\nまってよ～", 0, 0, 1, 1, 1020, 0, "茜 ミミ");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("あ…あの…えっと…\n栗…林…くるみ…です……", 0, 1, 0, "ふぇぇぇぇぇん……", 2, 1.5, "あの……\nふぇ……", 0, 0, 1, 1, 1021, 0, "栗林 くるみ");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("風宮よりです。\nあああああ！", 0, 1, 0, "なんてありがとうございます！", 2, 1.4, "こんな私に貴重な時間を\n割いていただき、", 0, 0, 1, 1, 1022, 0, "風宮 より");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("私、アヤネ！\nぷうきちと一緒についてってあげるね！", 0, 1, 0, "私こっち行きたいー\nね、早く早くー", 2, 1.5, "おにいちゃんどこいくの？\nえ？", 0, 0, 1, 1, 1023, 0, "北条 綾音");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("わっ…わっ…私、\n天野すずめといいます！", 0, 1, 0, "これて何か違う…\nあああすみません！", 2, 1.4, "ふ、不束者ですが\nどうぞ末永く…って、", 0, 0, 1, 1, 1025, 0, "天野 すずめ");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("……クスクス…私は\n…倉石恵理子……", 0, 1, 0, "離しませんわ………\n絶対に…!!", 2, 1.4, "あなたは…運命の……\n伴侶……", 0, 0, 1, 1, 1027, 0, "倉石 恵理子");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？", 0, 1, 0, "…そうでしょ？？", 2, 1.4, "その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！", 0, 0, 1, 1, 1028, 0, "佐々木 咲恋");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("桜井望だよ！\nよろしくねっ", 0, 1, 0, "あはは、\n私もまだまだだなぁ～", 2, 1.4, "ぇっと…\nキミ、私のこと知らないの?!", 0, 0, 1, 1, 1029, 0, "桜井 望");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("デケデケデンっ！", 0, 1, 0, "ショーグン、\nワタシと一緒に天下統一デース！", 2, 1.4, "初めまして、\n私はニノン・ジュベール申すデス！", 0, 0, 1, 1, 1030, 0, "ニノン・ジュベール");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("上喜しのぶです。\n手元のドクロが父です。", 0, 1, 0, "おかしいですね……", 2, 1.4, "でもって私の隣にいるのが……\nえ、見えない？", 0, 0, 1, 1, 1031, 0, "上喜 しのぶ");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("目指すはビッグな\nお笑い芸人だっぺ！", 0, 1, 0, "そう、\nオラのボケに突っ込める相方が…！", 2, 1.5, "けんども\nそれには足りないモンが…", 0, 0, 1, 1, 1033, 0, "野戸まひる");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！", 0, 1, 0, "ちょ\nちょっと一杯飲んできます…！", 2, 1.4, "ちょっと緊張しちゃって…", 0, 0, 1, 1, 1034, 0, "綾瀬 ゆかり");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("氷川鏡華…です", 0, 1, 0, "これ以上お話しすることは…\nないです！", 2, 1.5, "知らない人とは話しちゃいけないので", 0, 0, 1, 1, 1036, 0, "氷川 鏡華");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("柏崎…栞です。", 0, 1, 0, "私体が弱いから、\n30分に一度休憩しないと\nいけないんです。", 2, 1.4, "……あ、アラーム。", 0, 0, 1, 1, 1038, 0, "柏崎 栞");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ふ、双葉碧です。", 0, 1, 0, "野に咲く花が、\n唯一の話相手です。", 2, 1.4, "私、一人も友達がいなくて……", 0, 0, 1, 1, 1040, 0, "双葉 碧");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("三角千歌です。", 0, 1, 0, "そう思っています。", 2, 1.4, "私の歌声で、\n皆さんが幸せになってくれたらいいなって…", 0, 0, 1, 1, 1042, 0, "三角 千歌");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("安芸真琴だ。", 0, 1, 0, "う、疑ってすまなかったな…", 2, 1.4, "あぁ？\nお前のそいつの仲間か？", 0, 0, 1, 1, 1043, 0, "安芸 真琴");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("わらわこそは夜を総べる者！", 0, 1, 0, "わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！", 2, 1.4, "生けとし生ける全ての者よ！", 0, 0, 1, 1, 1044, 0, "イリヤ・オーンスタイン");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("そこで騎士は妖精を乱暴に……", 0, 1, 0, "ｌク、クウカに何かご用ですか!?", 2, 1.4, "ぐふふふふ……はっ！", 0, 0, 1, 1, 1045, 0, "遠見 空花");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("宮坂たまきにゃ♪\n猫はいいにゃよ？", 0, 1, 0, "う～ん…\n猫ってホントに最高にゃ～♪", 2, 1.4, "自由気ままで♪\n寝て遊んで、食べてケンカして…", 0, 0, 1, 1, 1046, 0, "宮坂たまき");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("大神美冬よ！", 0, 1, 0, "…と思ったら\nバイトの時間だ！\nまたあとでね！", 2, 1.4, "それでは早速クエストに…", 0, 0, 1, 1, 1048, 0, "大神 美冬");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("星野静流だよ！", 0, 1, 0, "お姉ちゃんがぜ～んぶ\nやってあげるからね！", 2, 1.4, "クエストもバトルも\n掃除も洗濯も", 0, 0, 1, 1, 1049, 0, "星野静流");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("アタシは玉泉美咲。", 0, 1, 0, "学校では誰もが憧れる\nアイドル的な存在ってやつよ♪", 2, 1.5, "見ての通りの\nセクシー美少女で", 0, 0, 1, 1, 1050, 0, "玉泉美咲");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("？？？", 0, 1, 0, "？？？？", 2, 1.4, "？？？？", 0, 0, 1, 1, 1052, 0, "リマ");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("モニカ・ヴァイスヴィントだ。", 0, 1, 0, "そ、そこまでいうなら\nもらってやる", 2, 1.5, "菓子でつろうなどと\n稚拙な策を……", 0, 0, 1, 1, 1053, 0, "モニカ・ヴァイスヴィント");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("モニカ・ヴァイスヴィントだ。", 0, 1, 0, "そ、そこまでいうなら\nもらってやる", 2, 1.5, "菓子でつろうなどと\n稚拙な策を……", 0, 0, 1, 1, 1058, 0, "ペコリーヌ");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("モニカ・ヴァイスヴィントだ。", 0, 1, 0, "そ、そこまでいうなら\nもらってやる", 2, 1.5, "菓子でつろうなどと\n稚拙な策を……", 0, 0, 1, 1, 1059, 0, "コッコロ");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("モニカ・ヴァイスヴィントだ。", 0, 1, 0, "そ、そこまでいうなら\nもらってやる", 2, 1.5, "菓子でつろうなどと\n稚拙な策を……", 0, 0, 1, 1, 1060, 0, "キャル");
